if (! function_exists('two_way_sync')) {
    function two_way_sync($db_a, $db_b, $table, $primary_key = null, $direction = null, $conflict_strategy = null, $timestamp_column = null, $mode = null, $create_table = null)
    {
            $db_a = $db_a ?? '';
            $db_b = $db_b ?? '';
            $table = $table ?? '';
            $primary_key = $primary_key ?? 'id';
            $direction = $direction ?? 'a_to_b';
            $conflict_strategy = $conflict_strategy ?? 'a_wins';
            $timestamp_column = $timestamp_column ?? 'updated_at';
            $mode = $mode ?? 'diff';
            $create_table = $create_table ?? false;

            if (empty($db_a) || empty($db_b) || empty($table)) {
                return ['success' => false, 'error' => 'db_a, db_b, and table are required.'];
            }

            $valid_directions = ['a_to_b', 'b_to_a', 'bidirectional'];
            if (!in_array($direction, $valid_directions)) {
                return ['success' => false, 'error' => "Invalid direction. Must be: " . implode(', ', $valid_directions)];
            }

            $valid_strategies = ['a_wins', 'b_wins', 'keep_newer'];
            if (!in_array($conflict_strategy, $valid_strategies)) {
                return ['success' => false, 'error' => "Invalid conflict_strategy. Must be: " . implode(', ', $valid_strategies)];
            }

            $workspace = __DIR__ . '/../workspace';
            $path_a = $workspace . '/' . basename($db_a);
            $path_b = $workspace . '/' . basename($db_b);

            if (!file_exists($path_a)) {
                return ['success' => false, 'error' => "Database A not found: $db_a (looked in workspace)"];
            }
            if (!file_exists($path_b)) {
                if ($create_table && file_exists($path_a)) {
                    // B doesn't exist — will create it
                } else {
                    return ['success' => false, 'error' => "Database B not found: $db_b (looked in workspace)", 'note' => 'Set create_table=true to auto-create B from A\'s schema.'];
                }
            }

            // Helper: open DB and connect
            $open_db = function($path) {
                try {
                    $pdo = new PDO("sqlite:$path");
                    $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                    $pdo->exec("PRAGMA journal_mode=WAL");
                    return $pdo;
                } catch (Exception $e) {
                    return null;
                }
            };

            $pdo_a = $open_db($path_a);
            if (!$pdo_a) {
                return ['success' => false, 'error' => "Failed to open database A: $db_a"];
            }

            // If B doesn't exist and create_table is set, create it
            if (!file_exists($path_b) && $create_table) {
                try {
                    $dir = dirname($path_b);
                    if (!is_dir($dir)) @mkdir($dir, 0777, true);
                    $pdo_b = new PDO("sqlite:$path_b");
                    $pdo_b->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
                    $pdo_b->exec("PRAGMA journal_mode=WAL");

                    // Get CREATE TABLE statement from A
                    $schema = $pdo_a->query("SELECT sql FROM sqlite_master WHERE type='table' AND name=" . $pdo_a->quote($table))->fetch(PDO::FETCH_COLUMN);
                    if ($schema) {
                        $pdo_b->exec($schema);
                        // Also copy indexes
                        $indexes = $pdo_a->query("SELECT sql FROM sqlite_master WHERE type='index' AND tbl_name=" . $pdo_a->quote($table) . " AND sql IS NOT NULL")->fetchAll(PDO::FETCH_COLUMN);
                        foreach ($indexes as $idx_sql) {
                            try { $pdo_b->exec($idx_sql); } catch (Exception $e) {}
                        }
                    } else {
                        return ['success' => false, 'error' => "Table '$table' not found in database A, cannot create in B."];
                    }
                } catch (Exception $e) {
                    return ['success' => false, 'error' => 'Failed to create database B: ' . $e->getMessage()];
                }
            } else {
                $pdo_b = $open_db($path_b);
                if (!$pdo_b) {
                    return ['success' => false, 'error' => "Failed to open database B: $db_b"];
                }
            }

            // Verify table exists in both databases
            $table_exists = function($pdo, $tbl) {
                try {
                    $r = $pdo->query("SELECT count(*) FROM sqlite_master WHERE type='table' AND name=" . $pdo->quote($tbl))->fetch(PDO::FETCH_COLUMN);
                    return $r > 0;
                } catch (Exception $e) {
                    return false;
                }
            };

            if (!$table_exists($pdo_a, $table)) {
                return ['success' => false, 'error' => "Table '$table' not found in database A."];
            }
            if (!$table_exists($pdo_b, $table)) {
                return ['success' => false, 'error' => "Table '$table' not found in database B.", 'note' => 'Use create_table=true to auto-create it from A\'s schema.'];
            }

            // Get column info
            $get_columns = function($pdo, $tbl) {
                try {
                    $cols = $pdo->query("PRAGMA table_info(" . $pdo->quote($tbl) . ")")->fetchAll(PDO::FETCH_ASSOC);
                    return array_map(function($c) { return $c['name']; }, $cols);
                } catch (Exception $e) {
                    return [];
                }
            };

            $cols_a = $get_columns($pdo_a, $table);
            $cols_b = $get_columns($pdo_b, $table);
            $common_cols = array_intersect($cols_a, $cols_b);

            if (empty($common_cols)) {
                return ['success' => false, 'error' => "No common columns found between the two databases for table '$table'."];
            }

            if (!in_array($primary_key, $common_cols)) {
                return ['success' => false, 'error' => "Primary key column '$primary_key' not found in both databases."];
            }

            // Read all rows from both databases
            $read_rows = function($pdo, $tbl, $cols, $pk) {
                try {
                    $col_list = implode(', ', array_map(function($c) use ($pdo) { return $pdo->quote($c); }, $cols));
                    // Use double quotes for identifiers, single quotes for values
                    $col_list = '"' . implode('", "', $cols) . '"';
                    $stmt = $pdo->query("SELECT {$col_list} FROM \"{$tbl}\"");
                    $rows = [];
                    while ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {
                        $key = (string)$row[$pk];
                        // Compute a row hash for comparison (excluding the pk itself for update detection)
                        $hash_data = '';
                        foreach ($row as $k => $v) {
                            if ($k !== $pk) {
                                $hash_data .= $k . '=' . ($v ?? 'NULL') . '|';
                            }
                        }
                        $rows[$key] = [
                            'data' => $row,
                            'hash' => md5($hash_data),
                        ];
                    }
                    return $rows;
                } catch (Exception $e) {
                    return null;
                }
            };

            $rows_a = $read_rows($pdo_a, $table, $common_cols, $primary_key);
            $rows_b = $read_rows($pdo_b, $table, $common_cols, $primary_key);

            if ($rows_a === null) {
                return ['success' => false, 'error' => "Failed to read rows from database A table '$table'."];
            }
            if ($rows_b === null) {
                return ['success' => false, 'error' => "Failed to read rows from database B table '$table'."];
            }

            // Compute differences
            $keys_a = array_keys($rows_a);
            $keys_b = array_keys($rows_b);
            $set_a = array_flip($keys_a);
            $set_b = array_flip($keys_b);

            $in_a_not_b = [];
            foreach ($keys_a as $k) {
                if (!isset($set_b[$k])) {
                    $in_a_not_b[] = $k;
                }
            }

            $in_b_not_a = [];
            foreach ($keys_b as $k) {
                if (!isset($set_a[$k])) {
                    $in_b_not_a[] = $k;
                }
            }

            $changed = [];
            $conflicts = [];
            foreach ($keys_a as $k) {
                if (isset($set_b[$k])) {
                    if ($rows_a[$k]['hash'] !== $rows_b[$k]['hash']) {
                        $changed[] = $k;
                    }
                }
            }

            // For bidirectional mode, find true conflicts (different data in both)
            if ($direction === 'bidirectional') {
                foreach ($changed as $k) {
                    $conflicts[] = $k;
                }
            }

            $diff_report = [
                'summary' => [
                    'table' => $table,
                    'rows_in_a' => count($rows_a),
                    'rows_in_b' => count($rows_b),
                    'in_a_not_b' => count($in_a_not_b),
                    'in_b_not_a' => count($in_b_not_a),
                    'changed' => count($changed),
                    'conflicts' => count($conflicts),
                    'columns' => $common_cols,
                    'primary_key' => $primary_key,
                ],
                'in_a_not_b' => $in_a_not_b,
                'in_b_not_a' => $in_b_not_a,
                'changed' => array_map(function($k) use ($rows_a, $rows_b) {
                    return [
                        'key' => $k,
                        'a' => $rows_a[$k]['data'],
                        'b' => $rows_b[$k]['data'],
                    ];
                }, array_slice($changed, 0, 50)),
            ];

            // If diff mode, return report without modifying data
            if ($mode === 'diff') {
                return [
                    'success' => true,
                    'mode' => 'diff',
                    'databases' => ['a' => $db_a, 'b' => $db_b],
                    'sync_direction' => $direction,
                    'conflict_strategy' => $conflict_strategy,
                    'note' => 'Diff mode — no data was modified.',
                    ...$diff_report,
                ];
            }

            // === SYNC MODE ===
            $operations = [];
            $errors = 0;

            $build_insert = function($pdo, $tbl, $row_data) {
                $cols = array_keys($row_data);
                $col_list = '"' . implode('", "', $cols) . '"';
                $placeholders = implode(', ', array_fill(0, count($cols), '?'));
                $sql = "INSERT OR REPLACE INTO \"{$tbl}\" ({$col_list}) VALUES ({$placeholders})";
                return ['sql' => $sql, 'values' => array_values($row_data)];
            };

            $build_delete = function($pdo, $tbl, $pk_col, $pk_val) {
                $sql = "DELETE FROM \"{$tbl}\" WHERE \"{$pk_col}\" = ?";
                return ['sql' => $sql, 'values' => [$pk_val]];
            };

            // Determine which DB is source and which is target
            $source_pdo = null;
            $target_pdo = null;
            $source_name = '';
            $target_name = '';

            switch ($direction) {
                case 'a_to_b':
                    $source_pdo = $pdo_a;
                    $target_pdo = $pdo_b;
                    $source_name = 'A';
                    $target_name = 'B';
                    break;
                case 'b_to_a':
                    $source_pdo = $pdo_b;
                    $target_pdo = $pdo_a;
                    $source_name = 'B';
                    $target_name = 'A';
                    break;
                case 'bidirectional':
                    // Will handle each side separately
                    break;
            }

            if ($direction !== 'bidirectional') {
                // Directional sync: rows in source not in target → INSERT into target
                // Rows in target not in source → DELETE from target (if not in source)
                // Rows changed → UPDATE target with source version

                $source_rows = ($source_name === 'A') ? $rows_a : $rows_b;
                $target_rows = ($target_name === 'A') ? $rows_a : $rows_b;
                $target_keys = array_flip(array_keys($target_rows));

                // INSERT: rows in source not in target
                foreach ($source_rows as $k => $sr) {
                    if (!isset($target_keys[$k])) {
                        try {
                            $op = $build_insert($target_pdo, $table, $sr['data']);
                            $target_pdo->prepare($op['sql'])->execute($op['values']);
                            $operations[] = ['type' => 'insert', 'key' => $k, 'target' => $target_name];
                        } catch (Exception $e) {
                            $errors++;
                            $operations[] = ['type' => 'insert_error', 'key' => $k, 'error' => $e->getMessage()];
                        }
                    }
                }

                // DELETE: rows in target not in source
                foreach ($target_rows as $k => $tr) {
                    if (!isset($set_a[$k]) && !isset($set_b[$k])) continue;
                    $in_source = ($source_name === 'A') ? isset($set_a[$k]) : isset($set_b[$k]);
                    if (!$in_source) {
                        try {
                            $op = $build_delete($target_pdo, $table, $primary_key, $k);
                            $target_pdo->prepare($op['sql'])->execute($op['values']);
                            $operations[] = ['type' => 'delete', 'key' => $k, 'target' => $target_name];
                        } catch (Exception $e) {
                            $errors++;
                            $operations[] = ['type' => 'delete_error', 'key' => $k, 'error' => $e->getMessage()];
                        }
                    }
                }

                // UPDATE: changed rows
                foreach ($source_rows as $k => $sr) {
                    if (isset($target_keys[$k])) {
                        $target_hash = $target_rows[$k]['hash'] ?? '';
                        if ($sr['hash'] !== $target_hash) {
                            try {
                                $op = $build_insert($target_pdo, $table, $sr['data']);
                                $target_pdo->prepare($op['sql'])->execute($op['values']);
                                $operations[] = ['type' => 'update', 'key' => $k, 'target' => $target_name];
                            } catch (Exception $e) {
                                $errors++;
                                $operations[] = ['type' => 'update_error', 'key' => $k, 'error' => $e->getMessage()];
                            }
                        }
                    }
                }
            } else {
                // Bidirectional merge
                // Rows only in A → INSERT into B
                foreach ($in_a_not_b as $k) {
                    try {
                        $op = $build_insert($pdo_b, $table, $rows_a[$k]['data']);
                        $pdo_b->prepare($op['sql'])->execute($op['values']);
                        $operations[] = ['type' => 'insert', 'key' => $k, 'target' => 'B'];
                    } catch (Exception $e) {
                        $errors++;
                        $operations[] = ['type' => 'insert_error', 'key' => $k, 'target' => 'B', 'error' => $e->getMessage()];
                    }
                }

                // Rows only in B → INSERT into A
                foreach ($in_b_not_a as $k) {
                    try {
                        $op = $build_insert($pdo_a, $table, $rows_b[$k]['data']);
                        $pdo_a->prepare($op['sql'])->execute($op['values']);
                        $operations[] = ['type' => 'insert', 'key' => $k, 'target' => 'A'];
                    } catch (Exception $e) {
                        $errors++;
                        $operations[] = ['type' => 'insert_error', 'key' => $k, 'target' => 'A', 'error' => $e->getMessage()];
                    }
                }

                // Conflicting rows: use conflict_strategy
                foreach ($changed as $k) {
                    $a_data = $rows_a[$k]['data'];
                    $b_data = $rows_b[$k]['data'];
                    $winner = null;
                    $loser = null;

                    switch ($conflict_strategy) {
                        case 'a_wins':
                            $winner = 'A';
                            break;
                        case 'b_wins':
                            $winner = 'B';
                            break;
                        case 'keep_newer':
                            $a_ts = $a_data[$timestamp_column] ?? '';
                            $b_ts = $b_data[$timestamp_column] ?? '';
                            $winner = ($a_ts >= $b_ts) ? 'A' : 'B';
                            break;
                    }

                    if ($winner === 'A') {
                        try {
                            $op = $build_insert($pdo_b, $table, $a_data);
                            $pdo_b->prepare($op['sql'])->execute($op['values']);
                            $operations[] = ['type' => 'conflict_resolved', 'key' => $k, 'winner' => 'A'];
                        } catch (Exception $e) {
                            $errors++;
                            $operations[] = ['type' => 'conflict_error', 'key' => $k, 'error' => $e->getMessage()];
                        }
                    } else {
                        try {
                            $op = $build_insert($pdo_a, $table, $b_data);
                            $pdo_a->prepare($op['sql'])->execute($op['values']);
                            $operations[] = ['type' => 'conflict_resolved', 'key' => $k, 'winner' => 'B'];
                        } catch (Exception $e) {
                            $errors++;
                            $operations[] = ['type' => 'conflict_error', 'key' => $k, 'error' => $e->getMessage()];
                        }
                    }
                }
            }

            // Count by type
            $op_counts = [];
            foreach ($operations as $op) {
                $t = $op['type'];
                $op_counts[$t] = ($op_counts[$t] ?? 0) + 1;
            }

            return [
                'success' => true,
                'mode' => 'sync',
                'databases' => ['a' => $db_a, 'b' => $db_b],
                'table' => $table,
                'sync_direction' => $direction,
                'conflict_strategy' => $conflict_strategy,
                'changes' => [
                    'inserts' => ($op_counts['insert'] ?? 0),
                    'updates' => ($op_counts['update'] ?? 0),
                    'deletes' => ($op_counts['delete'] ?? 0),
                    'conflicts_resolved' => ($op_counts['conflict_resolved'] ?? 0),
                    'errors' => $errors,
                ],
                'operations' => $operations,
                ...$diff_report,
            ];
    }
}
